import * as React from 'react';
import axios from 'axios';
import { useParams } from 'react-router-dom';
import { useEffect, useState } from 'react';
import { Container, Typography, Paper, CircularProgress, Alert } from '@mui/material';

export default function QuestionDetail() {
  const { id } = useParams();
  const [question, setQuestion] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    axios.get(`http://localhost:8080/api/questions/id`)
      .then(res => {
        setQuestion(res.data);
        setLoading(false);
      })
      .catch(() => {
        setError('Không thể tải chi tiết câu hỏi');
        setLoading(false);
      });
  }, [id]);

  if (loading) return <Container sx={{mt:4}}><CircularProgress /></Container>;
  if (error) return <Container sx={{mt:4}}><Alert severity="error">{error}</Alert></Container>;
  if (!question) return null;

  return (
    <Container maxWidth="md" sx={{mt:6}}>
      <Paper elevation={3} sx={{p:4}}>
        <Typography variant="h4" gutterBottom>{question.title}</Typography>
        <Typography color="text.secondary" sx={{mb:2}}>{question.content}</Typography>
        {/* Hiển thị thêm các thông tin khác nếu có */}
      </Paper>
    </Container>
  );
}
